const svg=$('#ge-svg'), pick=$('#ge-pick'),
      u0S=$('#ge-u0'), v0S=$('#ge-v0'), angS=$('#ge-ang'), lenS=$('#ge-len'),
      out = $('#ge-out');

// Each surface supplies x(u,v) and a function to compute the induced metric
// and Christoffel symbols numerically. We integrate the geodesic ODE in (u,v).
const SURF = {
  sphere: {
    uMin:0.1, uMax:Math.PI-0.1, vMin:0, vMax:2*Math.PI, periodic:[false,true],
    x:(u,v)=>[Math.sin(u)*Math.cos(v), Math.sin(u)*Math.sin(v), Math.cos(u)],
    label:'unit sphere'
  },
  cylinder: {
    uMin:0, uMax:2*Math.PI, vMin:-1.5, vMax:1.5, periodic:[true,false],
    x:(u,v)=>[Math.cos(u), Math.sin(u), v],
    label:'cylinder'
  },
  torus: {
    uMin:0, uMax:2*Math.PI, vMin:0, vMax:2*Math.PI, periodic:[true,true],
    x:(u,v)=>{const R=1, r=0.4;
      return [(R+r*Math.cos(v))*Math.cos(u), (R+r*Math.cos(v))*Math.sin(u), r*Math.sin(v)];},
    label:'torus (R=1, r=0.4)'
  },
  cone: {
    uMin:0.05, uMax:1.5, vMin:0, vMax:2*Math.PI, periodic:[false,true],
    // z = u (height along axis), radius = u·tan(α), α = 30°
    x:(u,v)=>{const a=Math.tan(Math.PI/6);
      return [a*u*Math.cos(v), a*u*Math.sin(v), u];},
    label:'cone (half-angle 30°)'
  },
  saddle: {
    uMin:-1.2, uMax:1.2, vMin:-1.2, vMax:1.2, periodic:[false,false],
    x:(u,v)=>[u, v, 0.5*(u*u - v*v)],
    label:'saddle z = ½(u² − v²)'
  }
};

// numeric partial derivatives of x(u,v)
function partials(S, u, v, h=1e-4){
  const xu = vscl(vsub(S.x(u+h,v), S.x(u-h,v)), 1/(2*h));
  const xv = vscl(vsub(S.x(u,v+h), S.x(u,v-h)), 1/(2*h));
  return {xu, xv};
}
function metric(S, u, v){
  const {xu, xv} = partials(S,u,v);
  return {E:vdot(xu,xu), F:vdot(xu,xv), G:vdot(xv,xv)};
}
function christoffel(S, u, v){
  // second derivatives via finite differences
  const h = 1e-3;
  const {xu:xu0, xv:xv0} = partials(S,u,v,h);
  const {xu:xuu1, xv:xvu1} = partials(S,u+h,v,h);
  const {xu:xuu2, xv:xvu2} = partials(S,u-h,v,h);
  const {xu:xuv1, xv:xvv1} = partials(S,u,v+h,h);
  const {xu:xuv2, xv:xvv2} = partials(S,u,v-h,h);
  const xuu = vscl(vsub(xuu1, xuu2), 1/(2*h));
  const xvv = vscl(vsub(xvv1, xvv2), 1/(2*h));
  const xuv = vscl(vsub(xuv1, xuv2), 1/(2*h));
  const {xu, xv} = partials(S,u,v,h);
  const E = vdot(xu,xu), F = vdot(xu,xv), G = vdot(xv,xv);
  const det = E*G - F*F;
  // In 2D: want Γ^k_ij where x_{ij} = Γ^1_{ij} x_u + Γ^2_{ij} x_v + L_{ij} n.
  // Tangential component: [Γ^1_{ij}, Γ^2_{ij}] satisfies
  //   [E F; F G] [Γ^1; Γ^2] = [ x_{ij}·x_u ; x_{ij}·x_v ]
  function solve(a,b){
    // (1/det) [ G -F; -F E] [a;b]
    return [(G*a - F*b)/det, (-F*a + E*b)/det];
  }
  const g_uu = solve(vdot(xuu,xu), vdot(xuu,xv));
  const g_uv = solve(vdot(xuv,xu), vdot(xuv,xv));
  const g_vv = solve(vdot(xvv,xu), vdot(xvv,xv));
  return {
    G1: [[g_uu[0], g_uv[0]],[g_uv[0], g_vv[0]]],
    G2: [[g_uu[1], g_uv[1]],[g_uv[1], g_vv[1]]],
    E, F, G
  };
}

function rk4Step(S, state, dt){
  function deriv(s){
    const [u,v,du,dv] = s;
    const {G1, G2} = christoffel(S, u, v);
    const ddu = -(G1[0][0]*du*du + 2*G1[0][1]*du*dv + G1[1][1]*dv*dv);
    const ddv = -(G2[0][0]*du*du + 2*G2[0][1]*du*dv + G2[1][1]*dv*dv);
    return [du, dv, ddu, ddv];
  }
  const k1 = deriv(state);
  const k2 = deriv(state.map((s,i)=>s + dt/2*k1[i]));
  const k3 = deriv(state.map((s,i)=>s + dt/2*k2[i]));
  const k4 = deriv(state.map((s,i)=>s + dt*k3[i]));
  return state.map((s,i)=>s + dt/6*(k1[i] + 2*k2[i] + 2*k3[i] + k4[i]));
}

function integrate(S, u0, v0, angle, totalLen, nSteps=800){
  // pick initial direction in (u,v) with unit speed in the metric
  const {E, F, G} = metric(S, u0, v0);
  // want w = [cos(angle), sin(angle)] in orthonormal tangent basis;
  // convert to (u,v) basis by Gram-Schmidt: ê1 = xu/√E, ê2 = (xv - (F/E)xu)/√(G - F²/E)
  // so w in (u,v) coords = cosθ·(1/√E, 0) + sinθ·(-F/(E√(G-F²/E)), 1/√(G-F²/E))
  const sE = Math.sqrt(E);
  const GmFE = G - F*F/E;
  const sGmFE = Math.sqrt(Math.max(GmFE, 1e-9));
  const du0 = Math.cos(angle)/sE - Math.sin(angle)*F/(E*sGmFE);
  const dv0 = Math.sin(angle)/sGmFE;
  const dt = totalLen / nSteps;
  let state = [u0, v0, du0, dv0];
  const pts = [[u0,v0]];
  for(let i=0;i<nSteps;i++){
    state = rk4Step(S, state, dt);
    // handle periodic coords
    if(S.periodic[0]){ const span=S.uMax-S.uMin; state[0] = ((state[0]-S.uMin)%span + span)%span + S.uMin; }
    if(S.periodic[1]){ const span=S.vMax-S.vMin; state[1] = ((state[1]-S.vMin)%span + span)%span + S.vMin; }
    if(!isFinite(state[0]) || !isFinite(state[1])) break;
    // clamp non-periodic bounds
    if(!S.periodic[0] && (state[0]<S.uMin || state[0]>S.uMax)) break;
    if(!S.periodic[1] && (state[1]<S.vMin || state[1]>S.vMax)) break;
    pts.push([state[0], state[1]]);
  }
  return pts;
}

function draw(){
  svg.innerHTML='';
  const key = pick.value; const S = SURF[key];
  const yaw = view.yaw, pitch = view.pitch;

  const u0 = S.uMin + (S.uMax-S.uMin)*(+u0S.value/1000);
  const v0 = S.vMin + (S.vMax-S.vMin)*(+v0S.value/1000);
  const angle = +angS.value/100;
  const len = +lenS.value/100;

  // mesh (decimate during drag for responsiveness)
  const NU = view.dragging ? 14 : 24;
  const NV = view.dragging ? 18 : 32;
  const verts = [];
  for(let i=0;i<=NU;i++){
    const row=[];
    for(let j=0;j<=NV;j++){
      const uu = S.uMin + (S.uMax-S.uMin)*i/NU;
      const vv = S.vMin + (S.vMax-S.vMin)*j/NV;
      const P=S.x(uu,vv);
      const pp=proj3(P,yaw,pitch);
      row.push({P,pp});
    }
    verts.push(row);
  }
  let xmin=Infinity,xmax=-Infinity,ymin=Infinity,ymax=-Infinity;
  for(const row of verts) for(const {pp} of row){
    xmin=Math.min(xmin,pp[0]); xmax=Math.max(xmax,pp[0]);
    ymin=Math.min(ymin,pp[1]); ymax=Math.max(ymax,pp[1]);
  }
  const pad=0.2; xmin-=pad;xmax+=pad;ymin-=pad;ymax+=pad;
  const scale=Math.min(420/(xmax-xmin), 320/(ymax-ymin));
  const sx=x=>(x-(xmin+xmax)/2)*scale;
  const sy=y=>-(y-(ymin+ymax)/2)*scale;

  // draw surface with painter's algorithm
  const quads=[];
  for(let i=0;i<NU;i++) for(let j=0;j<NV;j++){
    const a=verts[i][j], b=verts[i+1][j], c=verts[i+1][j+1], d=verts[i][j+1];
    const zavg=(a.pp[2]+b.pp[2]+c.pp[2]+d.pp[2])/4;
    const v1 = vsub(c.P, a.P), v2 = vsub(d.P, b.P);
    const nn = vnorm(vcross(v1,v2));
    const light = vnorm([0.3,0.4,0.9]);
    const sh = Math.max(0.15, Math.abs(vdot(nn, light)));
    quads.push({a,b,c,d,zavg,sh});
  }
  quads.sort((x,y)=>x.zavg-y.zavg);
  for(const q of quads){
    const col = Math.round(60 + 100*q.sh);
    const pts=[q.a.pp,q.b.pp,q.c.pp,q.d.pp].map(p=>sx(p[0])+','+sy(p[1])).join(' ');
    svg.appendChild(SVG('polygon',{
      points:pts, fill:`rgb(${col-20},${col},${col+30})`,
      stroke:'#2a3242','stroke-width':0.3,'stroke-opacity':0.4
    }));
  }

  // integrate geodesic
  const pts = integrate(S, u0, v0, angle, len);
  let d='';
  let lastScreen = null;
  for(let i=0;i<pts.length;i++){
    const P = S.x(pts[i][0], pts[i][1]);
    const pp = proj3(P, yaw, pitch);
    const scr = [sx(pp[0]), sy(pp[1])];
    if(i===0){ d += 'M'+scr[0]+' '+scr[1]+' '; }
    else {
      // break on wrap for periodic coordinates to avoid long straight-line jumps
      if(lastScreen && Math.hypot(scr[0]-lastScreen[0], scr[1]-lastScreen[1]) > 60){
        d += 'M'+scr[0]+' '+scr[1]+' ';
      } else {
        d += 'L'+scr[0]+' '+scr[1]+' ';
      }
    }
    lastScreen = scr;
  }
  svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--blue)','stroke-width':2.4}));

  // start point
  const Pstart = S.x(u0, v0);
  const ppStart = proj3(Pstart, yaw, pitch);
  svg.appendChild(SVG('circle',{cx:sx(ppStart[0]), cy:sy(ppStart[1]), r:5, fill:'var(--yellow)', stroke:'#111','stroke-width':1.5}));
  // end point
  const last = pts[pts.length-1];
  const Pend = S.x(last[0], last[1]);
  const ppEnd = proj3(Pend, yaw, pitch);
  svg.appendChild(SVG('circle',{cx:sx(ppEnd[0]), cy:sy(ppEnd[1]), r:4, fill:'var(--pink)', stroke:'#111','stroke-width':1.3}));

  out.textContent =
    `${S.label}\n` +
    `start (u,v) = (${u0.toFixed(3)}, ${v0.toFixed(3)})\n` +
    `initial angle = ${angle.toFixed(3)} rad\n` +
    `geodesic length ≈ ${len.toFixed(2)}\n` +
    `integrated ${pts.length} RK4 steps\n` +
    `yellow = start · pink = current endpoint\n` +
    `yaw ${yaw.toFixed(2)} · pitch ${pitch.toFixed(2)} — drag to rotate`;
}

