  const NU=80, NV=120;
  let sum = 0;
  const du = (S.uMax-S.uMin)/NU, dv = (S.vMax-S.vMin)/NV;
  for(let i=0;i<NU;i++) for(let j=0;j<NV;j++){
    const u = S.uMin + (i+0.5)*du, v = S.vMin + (j+0.5)*dv;
    sum += S.K(u,v) * S.dA(u,v) * du * dv;
  }
  return sum;
}

function drawGenus2(){
  // stylized double-torus silhouette
  const d = 'M -130 0 C -130 -90 -30 -90 -30 -10 C -30 -90 30 -90 30 -10 C 30 -90 130 -90 130 0 C 130 90 30 90 30 10 C 30 90 -30 90 -30 10 C -30 90 -130 90 -130 0 Z';
  svg.appendChild(SVG('path',{d,fill:'rgba(131,193,103,0.15)',stroke:'var(--green)','stroke-width':2}));
  // two "holes"
  svg.appendChild(SVG('ellipse',{cx:-80,cy:0,rx:28,ry:10,fill:'rgba(0,0,0,0.4)',stroke:'var(--line)'}));
  svg.appendChild(SVG('ellipse',{cx:80,cy:0,rx:28,ry:10,fill:'rgba(0,0,0,0.4)',stroke:'var(--line)'}));
}

function draw(){
  svg.innerHTML='';
  const key = pick.value; const S = SURF[key];
  const chi = 2 - 2*S.genus;

  if(key === 'dtorus'){
    drawGenus2();
    const t1 = SVG('text',{x:0,y:-110,'text-anchor':'middle','font-size':14,fill:'#fff','font-weight':600});
    t1.textContent = 'double torus (genus 2)'; svg.appendChild(t1);
    out.textContent =
      `${S.label}\n` +
      `χ(Σ_2) = 2 − 2·2 = −2\n` +
      `2π·χ    = ${(2*Math.PI*chi).toFixed(4)}\n` +
      `∫ K dA  = −4π = ${(-4*Math.PI).toFixed(4)}  (by Gauss–Bonnet)\n` +
      `We represent this symbolically — triangulation V=10, E=24, F=12 ⇒ V−E+F = −2.`;
    return;
  }

  const intK = integrateK(S);

  // draw the surface with K color (decimate during drag)
  const NU = view.dragging ? 14 : 26;
  const NV = view.dragging ? 20 : 38;
  const yaw = view.yaw, pitch = view.pitch;
  const verts=[];
  for(let i=0;i<=NU;i++){
    const row=[];
    for(let j=0;j<=NV;j++){
      const uu = S.uMin + (S.uMax-S.uMin)*i/NU;
      const vv = S.vMin + (S.vMax-S.vMin)*j/NV;
      const P=S.x(uu,vv);
      const pp=proj3(P,yaw,pitch);
      row.push({P,pp,u:uu,v:vv,K:S.K(uu,vv)});
    }
    verts.push(row);
  }
  let xmin=Infinity,xmax=-Infinity,ymin=Infinity,ymax=-Infinity;
  for(const row of verts) for(const {pp} of row){
    xmin=Math.min(xmin,pp[0]); xmax=Math.max(xmax,pp[0]);
    ymin=Math.min(ymin,pp[1]); ymax=Math.max(ymax,pp[1]);
  }
  const pad=0.2; xmin-=pad;xmax+=pad;ymin-=pad;ymax+=pad;
  const scale=Math.min(460/(xmax-xmin), 320/(ymax-ymin));
  const sx=x=>(x-(xmin+xmax)/2)*scale;
  const sy=y=>-(y-(ymin+ymax)/2)*scale;

  let Kabs=0;
  for(const row of verts) for(const {K} of row) Kabs = Math.max(Kabs, Math.abs(K));
  if(Kabs<1e-6) Kabs=1;

  const quads=[];
  for(let i=0;i<NU;i++) for(let j=0;j<NV;j++){
    const a=verts[i][j], b=verts[i+1][j], c=verts[i+1][j+1], d=verts[i][j+1];
    const zavg=(a.pp[2]+b.pp[2]+c.pp[2]+d.pp[2])/4;
    const Kavg=(a.K+b.K+c.K+d.K)/4;
    quads.push({a,b,c,d,zavg,Kavg});
  }
  quads.sort((x,y)=>x.zavg-y.zavg);
  for(const q of quads){
    const pts=[q.a.pp,q.b.pp,q.c.pp,q.d.pp].map(p=>sx(p[0])+','+sy(p[1])).join(' ');
    svg.appendChild(SVG('polygon',{
      points:pts, fill:curvColor(q.Kavg/Kabs),
      stroke:'#2a3242','stroke-width':0.3,'stroke-opacity':0.5
    }));
  }

  out.textContent =
    `${S.label}\n` +
    `genus g = ${S.genus}, χ = 2 − 2g = ${chi}\n` +
    `2π·χ    = ${(2*Math.PI*chi).toFixed(4)}\n` +
    `∫ K dA  ≈ ${intK.toFixed(4)}   (numerical, ${80*120} midpoint samples)\n` +
    `match?  ${Math.abs(intK - 2*Math.PI*chi) < 0.05 ? 'yes ✓' : 'no'}\n` +
    `yaw ${yaw.toFixed(2)} · pitch ${pitch.toFixed(2)} — drag to rotate`;
}
