    const pp = proj3(V, yaw, pitch);
    return {P:V, pp, x: pp[0]*R, y: -pp[1]*R};
  });

  // Depth-sort faces by centroid z
  const fd = S.f.map(face => {
    const z = face.reduce((s,i) => s + pts[i].pp[2], 0) / face.length;
    return {face, z};
  }).sort((a,b) => a.z - b.z);

  // Draw translucent faces back-to-front; front faces get brighter fill and bolder edges
  for(const {face, z} of fd){
    const points = face.map(i => pts[i].x + ',' + pts[i].y).join(' ');
