      'stroke-width': front ? 1.6 : 0.7,
      'stroke-opacity': front ? 1 : 0.55
    }));
  }

  // Vertex markers
  for(const p of pts){
    const front = p.pp[2] > 0;
    svg.appendChild(SVG('circle', {
      cx: p.x, cy: p.y, r: front ? 5 : 3,
      fill: 'var(--yellow)',
      stroke: '#111', 'stroke-width': 1.1,
      'fill-opacity': front ? 1 : 0.5
    }));
  }

  // Readout (analytic values — same at every vertex for a Platonic solid)
  const faceAngle = (S.n - 2)*Math.PI/S.n;
  const defect    = 2*Math.PI - S.k*faceAngle;
  const totalDef  = S.V * defect;
  const chi       = S.V - S.E + S.F;
  const match     = Math.abs(totalDef - 2*Math.PI*chi) < 1e-9 ? '✓' : '✗';
  const deg       = r => (r*180/Math.PI);

  out.textContent =
    `${S.name}    V=${S.V}, E=${S.E}, F=${S.F}, regular ${S.n}-gon faces, ${S.k} faces meet at each vertex\n` +
    `Euler:      χ = V − E + F = ${S.V} − ${S.E} + ${S.F} = ${chi}\n` +
    `face angle: α = (n−2)π/n = ${S.n-2}π/${S.n} = ${deg(faceAngle).toFixed(2)}°\n` +
    `defect:     δ = 2π − k·α = ${deg(defect).toFixed(3)}° = ${defect.toFixed(4)} rad (same at every vertex)\n` +
    `Σ δ  (over ${S.V} vertices) = ${totalDef.toFixed(4)} rad = ${deg(totalDef).toFixed(2)}°\n` +
    `2π·χ                       = ${(2*Math.PI*chi).toFixed(4)} rad = ${deg(2*Math.PI*chi).toFixed(2)}°   ${match}\n` +
    `yaw ${yaw.toFixed(2)} · pitch ${pitch.toFixed(2)} — drag to rotate`;
}

