const svg=$('#hl-svg'), pick=$('#hl-pick'), thetaS=$('#hl-theta'), out=$('#hl-out');

function draw(){
  svg.innerHTML='';
  const key = pick.value;
  const yaw = view.yaw, pitch = view.pitch;
  // decimate wireframe density during drag
  const Nlat = view.dragging ? 30 : 60;
  const Nmer = view.dragging ? 30 : 60;
  // draw sphere wireframe
  const R = 1;
  // latitudes
  for(let k=-4;k<=4;k++){
    const lat = k*Math.PI/10;
    let d='';
    for(let j=0;j<=Nlat;j++){
      const lon = -Math.PI + 2*Math.PI*j/Nlat;
      const P=[R*Math.cos(lat)*Math.cos(lon), R*Math.cos(lat)*Math.sin(lon), R*Math.sin(lat)];
      const pp = proj3(P,yaw,pitch);
      d += (j===0?'M':'L') + pp[0]*140 + ' ' + (-pp[1]*140) + ' ';
    }
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'#2a3242','stroke-width':0.7}));
  }
  // meridians
  for(let k=0;k<12;k++){
    const lon = k*Math.PI/6;
    let d='';
    for(let j=0;j<=Nmer;j++){
      const lat = -Math.PI/2 + Math.PI*j/Nmer;
      const P=[R*Math.cos(lat)*Math.cos(lon), R*Math.cos(lat)*Math.sin(lon), R*Math.sin(lat)];
      const pp = proj3(P,yaw,pitch);
      d += (j===0?'M':'L') + pp[0]*140 + ' ' + (-pp[1]*140) + ' ';
    }
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'#2a3242','stroke-width':0.6}));
  }
  svg.appendChild(SVG('circle',{cx:0,cy:0,r:140,fill:'none',stroke:'var(--line)','stroke-width':1}));

  let holonomyAngle = 0;
  let areaEnclosed = 0;

  if(key === 'triangle'){
    // octant: equator from (1,0,0) to (0,1,0), then to north pole (0,0,1), then back to (1,0,0)
    // three geodesic arcs — each a quarter-circle
    const arcs = [
      { // equator, from e1 to e2
        P:(t)=>[Math.cos(t), Math.sin(t), 0], tMin:0, tMax:Math.PI/2
      },
      { // meridian at lon=π/2, from e2 to N
        P:(t)=>[0, Math.cos(t), Math.sin(t)], tMin:0, tMax:Math.PI/2
      },
      { // meridian at lon=0, from N back to e1
        P:(t)=>[Math.sin(t), 0, Math.cos(t)], tMin:0, tMax:Math.PI/2
      }
    ];
    drawArcs(arcs, yaw, pitch);
    holonomyAngle = Math.PI/2;  // area = π/2, K=1, so ∫K dA = π/2
    areaEnclosed = Math.PI/2;
  } else if(key === 'latitude'){
    const lat = Math.PI/2 - (+thetaS.value/1000);  // θ₀ = polar angle
    let d='';
    for(let j=0;j<=80;j++){
      const lon = 2*Math.PI*j/80;
      const P = [R*Math.cos(lat)*Math.cos(lon), R*Math.cos(lat)*Math.sin(lon), R*Math.sin(lat)];
      const pp = proj3(P,yaw,pitch);
      d += (j===0?'M':'L') + pp[0]*140 + ' ' + (-pp[1]*140) + ' ';
    }
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--cyan)','stroke-width':2.5}));
    // enclosed area above latitude θ₀ (measured from north pole with polar angle θ = π/2 − lat):
    // A = 2π R² (1 − cos θ) where θ = polar angle from pole
    const polar = Math.PI/2 - lat;
    areaEnclosed = 2*Math.PI*(1 - Math.cos(polar));
    holonomyAngle = areaEnclosed;  // ∫K dA on unit sphere
    // draw rotated vector on latitude
    const lon0 = 0;
    const P0 = [R*Math.cos(lat)*Math.cos(lon0), R*Math.cos(lat)*Math.sin(lon0), R*Math.sin(lat)];
    const pp0 = proj3(P0,yaw,pitch);
    // initial tangent vector pointing east (∂/∂φ direction)
    const east = [-Math.sin(lon0), Math.cos(lon0), 0];
    const ppEast = proj3(vadd(P0, vscl(east, 0.3)), yaw, pitch);
    drawArrow(svg, [pp0[0]*140, -pp0[1]*140], [ppEast[0]*140, -ppEast[1]*140],
      {color:'var(--yellow)', markerId:'hl-v0', width:2.2, pad2:6});
    // after transport: rotated by -holonomyAngle in tangent plane
    const north = vcross(vnorm(P0), east);
    const rotV = vadd(vscl(east, Math.cos(holonomyAngle)), vscl(north, Math.sin(holonomyAngle)));
    const ppR = proj3(vadd(P0, vscl(rotV, 0.3)), yaw, pitch);
    drawArrow(svg, [pp0[0]*140, -pp0[1]*140], [ppR[0]*140, -ppR[1]*140],
      {color:'var(--pink)', markerId:'hl-vR', width:2.2, pad2:6});
  } else {
    // small geodesic triangle near north pole
    const eps = +thetaS.value/2000;
    const arcs = [
      {P:(t)=>{const lat=Math.PI/2 - eps, lon=2*Math.PI*t/3;
        return [Math.cos(lat)*Math.cos(lon), Math.cos(lat)*Math.sin(lon), Math.sin(lat)];},
        tMin:0, tMax:1},
      {P:(t)=>{const lat=Math.PI/2 - eps, lon=2*Math.PI*(1+t)/3;
        return [Math.cos(lat)*Math.cos(lon), Math.cos(lat)*Math.sin(lon), Math.sin(lat)];},
        tMin:0, tMax:1},
      {P:(t)=>{const lat=Math.PI/2 - eps, lon=2*Math.PI*(2+t)/3;
        return [Math.cos(lat)*Math.cos(lon), Math.cos(lat)*Math.sin(lon), Math.sin(lat)];},
        tMin:0, tMax:1},
    ];
    drawArcs(arcs, yaw, pitch);
    areaEnclosed = 2*Math.PI*(1 - Math.cos(eps));
    holonomyAngle = areaEnclosed;
  }

  function drawArcs(arcs, yaw, pitch){
    for(const a of arcs){
      let d='';
      for(let j=0;j<=40;j++){
        const t = a.tMin + (a.tMax-a.tMin)*j/40;
        const pp = proj3(a.P(t), yaw, pitch);
        d += (j===0?'M':'L') + pp[0]*140 + ' ' + (-pp[1]*140) + ' ';
      }
      svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--cyan)','stroke-width':2.5}));
    }
  }

  out.textContent =
    `loop type: ${key}\n` +
    `enclosed area = ${areaEnclosed.toFixed(4)}\n` +
    `∫ K dA = ${areaEnclosed.toFixed(4)}   (K ≡ 1 on unit sphere)\n` +
    `holonomy angle = ${holonomyAngle.toFixed(4)} rad = ${(holonomyAngle*180/Math.PI).toFixed(2)}°\n` +
    `(cyan = loop, yellow = initial vector, pink = transported vector)\n` +
    `yaw ${yaw.toFixed(2)} · pitch ${pitch.toFixed(2)} — drag to rotate`;
}
pick.addEventListener('change',draw);
thetaS.addEventListener('input',draw);
const view = make3DDraggable(svg, draw, { yaw: 0.6, pitch: 0.5 });
draw();

const svg=$('#hl-svg'), pick=$('#hl-pick'), thetaS=$('#hl-theta'), out=$('#hl-out');

function draw(){
  svg.innerHTML='';
  const key = pick.value;
  const yaw = view.yaw, pitch = view.pitch;
  // decimate wireframe density during drag
  const Nlat = view.dragging ? 30 : 60;
  const Nmer = view.dragging ? 30 : 60;
  // draw sphere wireframe
  const R = 1;
  // latitudes
  for(let k=-4;k<=4;k++){
    const lat = k*Math.PI/10;
    let d='';
    for(let j=0;j<=Nlat;j++){
      const lon = -Math.PI + 2*Math.PI*j/Nlat;
      const P=[R*Math.cos(lat)*Math.cos(lon), R*Math.cos(lat)*Math.sin(lon), R*Math.sin(lat)];
      const pp = proj3(P,yaw,pitch);
      d += (j===0?'M':'L') + pp[0]*140 + ' ' + (-pp[1]*140) + ' ';
    }
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'#2a3242','stroke-width':0.7}));
  }
  // meridians
  for(let k=0;k<12;k++){
    const lon = k*Math.PI/6;
    let d='';
    for(let j=0;j<=Nmer;j++){
      const lat = -Math.PI/2 + Math.PI*j/Nmer;
      const P=[R*Math.cos(lat)*Math.cos(lon), R*Math.cos(lat)*Math.sin(lon), R*Math.sin(lat)];
      const pp = proj3(P,yaw,pitch);
      d += (j===0?'M':'L') + pp[0]*140 + ' ' + (-pp[1]*140) + ' ';
    }
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'#2a3242','stroke-width':0.6}));
  }
  svg.appendChild(SVG('circle',{cx:0,cy:0,r:140,fill:'none',stroke:'var(--line)','stroke-width':1}));

  let holonomyAngle = 0;
  let areaEnclosed = 0;

  if(key === 'triangle'){
    // octant: equator from (1,0,0) to (0,1,0), then to north pole (0,0,1), then back to (1,0,0)
    // three geodesic arcs — each a quarter-circle
    const arcs = [
      { // equator, from e1 to e2
        P:(t)=>[Math.cos(t), Math.sin(t), 0], tMin:0, tMax:Math.PI/2
      },
      { // meridian at lon=π/2, from e2 to N
        P:(t)=>[0, Math.cos(t), Math.sin(t)], tMin:0, tMax:Math.PI/2
      },
      { // meridian at lon=0, from N back to e1
        P:(t)=>[Math.sin(t), 0, Math.cos(t)], tMin:0, tMax:Math.PI/2
      }
    ];
    drawArcs(arcs, yaw, pitch);
    holonomyAngle = Math.PI/2;  // area = π/2, K=1, so ∫K dA = π/2
    areaEnclosed = Math.PI/2;
  } else if(key === 'latitude'){
    const lat = Math.PI/2 - (+thetaS.value/1000);  // θ₀ = polar angle
    let d='';
    for(let j=0;j<=80;j++){
      const lon = 2*Math.PI*j/80;
      const P = [R*Math.cos(lat)*Math.cos(lon), R*Math.cos(lat)*Math.sin(lon), R*Math.sin(lat)];
      const pp = proj3(P,yaw,pitch);
      d += (j===0?'M':'L') + pp[0]*140 + ' ' + (-pp[1]*140) + ' ';
    }
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--cyan)','stroke-width':2.5}));
    // enclosed area above latitude θ₀ (measured from north pole with polar angle θ = π/2 − lat):
    // A = 2π R² (1 − cos θ) where θ = polar angle from pole
    const polar = Math.PI/2 - lat;
    areaEnclosed = 2*Math.PI*(1 - Math.cos(polar));
    holonomyAngle = areaEnclosed;  // ∫K dA on unit sphere
    // draw rotated vector on latitude
    const lon0 = 0;
    const P0 = [R*Math.cos(lat)*Math.cos(lon0), R*Math.cos(lat)*Math.sin(lon0), R*Math.sin(lat)];
    const pp0 = proj3(P0,yaw,pitch);
    // initial tangent vector pointing east (∂/∂φ direction)
    const east = [-Math.sin(lon0), Math.cos(lon0), 0];
    const ppEast = proj3(vadd(P0, vscl(east, 0.3)), yaw, pitch);
    drawArrow(svg, [pp0[0]*140, -pp0[1]*140], [ppEast[0]*140, -ppEast[1]*140],
      {color:'var(--yellow)', markerId:'hl-v0', width:2.2, pad2:6});
    // after transport: rotated by -holonomyAngle in tangent plane
    const north = vcross(vnorm(P0), east);
    const rotV = vadd(vscl(east, Math.cos(holonomyAngle)), vscl(north, Math.sin(holonomyAngle)));
    const ppR = proj3(vadd(P0, vscl(rotV, 0.3)), yaw, pitch);
    drawArrow(svg, [pp0[0]*140, -pp0[1]*140], [ppR[0]*140, -ppR[1]*140],
      {color:'var(--pink)', markerId:'hl-vR', width:2.2, pad2:6});
  } else {
    // small geodesic triangle near north pole
    const eps = +thetaS.value/2000;
    const arcs = [
      {P:(t)=>{const lat=Math.PI/2 - eps, lon=2*Math.PI*t/3;
        return [Math.cos(lat)*Math.cos(lon), Math.cos(lat)*Math.sin(lon), Math.sin(lat)];},
        tMin:0, tMax:1},
      {P:(t)=>{const lat=Math.PI/2 - eps, lon=2*Math.PI*(1+t)/3;
        return [Math.cos(lat)*Math.cos(lon), Math.cos(lat)*Math.sin(lon), Math.sin(lat)];},
        tMin:0, tMax:1},
      {P:(t)=>{const lat=Math.PI/2 - eps, lon=2*Math.PI*(2+t)/3;
        return [Math.cos(lat)*Math.cos(lon), Math.cos(lat)*Math.sin(lon), Math.sin(lat)];},
        tMin:0, tMax:1},
    ];
    drawArcs(arcs, yaw, pitch);
    areaEnclosed = 2*Math.PI*(1 - Math.cos(eps));
    holonomyAngle = areaEnclosed;
  }

  function drawArcs(arcs, yaw, pitch){
    for(const a of arcs){
      let d='';
      for(let j=0;j<=40;j++){
        const t = a.tMin + (a.tMax-a.tMin)*j/40;
        const pp = proj3(a.P(t), yaw, pitch);
        d += (j===0?'M':'L') + pp[0]*140 + ' ' + (-pp[1]*140) + ' ';
      }
      svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--cyan)','stroke-width':2.5}));
    }
  }

  out.textContent =
    `loop type: ${key}\n` +
    `enclosed area = ${areaEnclosed.toFixed(4)}\n` +
    `∫ K dA = ${areaEnclosed.toFixed(4)}   (K ≡ 1 on unit sphere)\n` +
    `holonomy angle = ${holonomyAngle.toFixed(4)} rad = ${(holonomyAngle*180/Math.PI).toFixed(2)}°\n` +
    `(cyan = loop, yellow = initial vector, pink = transported vector)\n` +
    `yaw ${yaw.toFixed(2)} · pitch ${pitch.toFixed(2)} — drag to rotate`;
}
pick.addEventListener('change',draw);
thetaS.addEventListener('input',draw);
const view = make3DDraggable(svg, draw, { yaw: 0.6, pitch: 0.5 });
draw();
